    function handlePromptCancel() {
        if (isPromptBusy) return;
        showPrompt = false;
        if (promptResolve) {
            promptResolve(null);
            promptResolve = null;
        }
    }

    function handlePromptInputKeydown(e: KeyboardEvent) {
        if (e.key === "Enter") {
            e.preventDefault();
            handlePromptConfirm();
            return;
        }
        if (e.key === "Escape") {
            e.preventDefault();
            handlePromptCancel();
        }
    }

    function showConfirmDialog(
        title: string,
        message: string,
    ): Promise<boolean> {
        return new Promise((resolve) => {
            confirmTitle = title;
            confirmMessage = message;
            showConfirm = true;
            confirmResolve = resolve;
        });
    }

    function handleConfirmConfirm() {
        if (confirmResolve) confirmResolve(true);
        showConfirm = false;
        confirmResolve = null;
    }

    function handleConfirmCancel() {
        if (confirmResolve) confirmResolve(false);
        showConfirm = false;
        confirmResolve = null;
    }

    function handlePromptOverlayClick(e: MouseEvent) {
        if (e.target === e.currentTarget) {
            handlePromptCancel();
        }
    }

    function handlePromptOverlayKeydown(e: KeyboardEvent) {
        if (e.key === "Escape") {
            handlePromptCancel();
        }
    }

    function handleConfirmOverlayClick(e: MouseEvent) {
        if (e.target === e.currentTarget) {
            handleConfirmCancel();
        }
    }

    function handleConfirmOverlayKeydown(e: KeyboardEvent) {
        if (e.key === "Escape") {
            handleConfirmCancel();
