    .file-tree {
        width: 240px;
        background: #fff;
        border-right: 1px solid #ddd;
        display: flex;
        flex-direction: column;
        flex-shrink: 0;
    }

    .tree-header {
        height: 40px; /* Matched with tabs-bar */
        padding: 0 16px;
        border-bottom: 1px solid #eee;
        background: #fafafa;
        display: flex;
        align-items: center;
        justify-content: space-between;
        box-sizing: border-box;
    }

    .tree-header h3 {
        margin: 0;
        font-size: 16px;
        color: #333;
        flex: 1;
    }

    .header-actions {
        display: flex;
        gap: 8px;
        flex-shrink: 0;
    }

    .icon-btn {
        background: transparent;
        border: none;
        cursor: pointer;
        padding: 4px;
        border-radius: 4px;
        font-size: 16px;
        display: flex;
        align-items: center;
        justify-content: center;
        transition: background 0.2s;
    }

    .icon-btn:hover:not(:disabled) {
        background: #e0e0e0;
    }

    .icon-btn:disabled {
        opacity: 0.3;
        cursor: default;
    }

    .icon-btn.dirty {
        color: #ff9800;
        filter: drop-shadow(0 0 2px rgba(255, 152, 0, 0.5));
    }

    .tree-content {
        flex: 1;
        overflow-y: auto;
