    .preview-pane {
        width: 320px; /* Standard Android/iPhone Width */
        background: #fff;
        display: flex;
        flex-direction: column;
        border-left: 1px solid #ddd;
    }

    .preview-header {
        height: 40px; /* Matched with tabs-bar */
        background: #fafafa;
        border-bottom: 1px solid #eee;
        display: flex;
        align-items: center;
        box-sizing: border-box;
    }

    .tabs {
        display: flex;
        height: 100%;
        width: 100%;
    }

    .tab {
        flex: 1;
        border: none;
        background: transparent;
        font-size: 16px; /* Matched with tree-header h3 */
        color: #666;
        cursor: pointer;
        border-bottom: 2px solid transparent;
        transition: all 0.2s;
        font-weight: bold; /* Matched with tree-header h3 */
    }

    .tab:hover {
        background: #f0f0f0;
        color: #333;
    }

    .tab.active {
        color: #2196f3;
        border-bottom: 2px solid #2196f3;
        background: #fff;
    }

    .preview-container {
        flex: 1; /* Grow vertically */
        width: 100%; /* Fill sidebar width */
        display: flex;
        flex-direction: column;
        overflow-y: hidden; /* Let iframe handle scroll, prevent double scrollbar */
        overflow-x: hidden; /* Prevent horizontal scrollbar */
        background: #f0f0f0; /* Darker background to distinguish phone frame */
        align-items: center; /* Center horizontally */
        justify-content: flex-start; /* Align to top (placeholder will center itself) */
