        box-shadow: 0 0 0 2px rgba(33, 150, 243, 0.2);
    }

    .fr-btn {
        padding: 4px 8px;
        border: 1px solid #bbb;
        border-radius: 4px;
        background: linear-gradient(to bottom, #fff, #e8e8e8);
