        font-size: 12px;
        display: flex;
        align-items: center;
        justify-content: center;
        white-space: nowrap;
    }

    .fr-btn-text {
        padding: 4px 10px;
    }

    .fr-btn:hover {
        background: linear-gradient(to bottom, #f5f5f5, #ddd);
        border-color: #999;
    }

    .fr-btn:active {
        background: #ddd;
    }

    .fr-danger {
        background: linear-gradient(to bottom, #fff0e6, #ffddcc);
        border-color: #e65c00;
    }

    .fr-danger:hover {
        background: linear-gradient(to bottom, #ffe6d9, #ffcc99);
    }

    .fr-close-btn {
        background: linear-gradient(to bottom, #fee, #fcc);
        border-color: #d99;
    }

    .fr-close-btn:hover {
        background: linear-gradient(to bottom, #fdd, #faa);
        border-color: #c66;
    }

