    .prompt-overlay {
        position: fixed;
        top: 0;
        left: 0;
        right: 0;
        bottom: 0;
        background: rgba(0, 0, 0, 0.5);
        display: flex;
        align-items: center;
        justify-content: center;
        z-index: 999999;
    }

    .prompt-dialog {
        background: white;
        border-radius: 12px;
        padding: 24px;
        min-width: 320px;
        box-shadow: 0 8px 32px rgba(0, 0, 0, 0.2);
    }

    .prompt-title {
        font-size: 16px;
        font-weight: 600;
        margin-bottom: 16px;
        color: #333;
    }

    .prompt-input {
        width: 100%;
        padding: 10px 12px;
        border: 1px solid #ddd;
        border-radius: 6px;
        font-size: 14px;
        margin-bottom: 16px;
        box-sizing: border-box;
    }

    .prompt-input:focus {
        outline: none;
        border-color: #4a90d9;
        box-shadow: 0 0 0 2px rgba(74, 144, 217, 0.2);
    }

    .prompt-options {
        margin-bottom: 20px;
    }

    .prompt-checkbox {
        display: flex;
        align-items: center;
        gap: 10px;
        font-size: 13px;
        color: #555;
        cursor: pointer;
        user-select: none;
    }

    .prompt-checkbox input {
        width: 16px;
        height: 16px;
        cursor: pointer;
        margin: 0;
    }

    .prompt-buttons {
        display: flex;
        justify-content: flex-end;
        gap: 8px;
    }

    .prompt-btn {
        padding: 8px 16px;
        border: none;
        border-radius: 6px;
        font-size: 14px;
        cursor: pointer;
        transition: all 0.2s;
    }

    .prompt-btn:disabled {
        opacity: 0.5;
        cursor: not-allowed;
    }

    .prompt-btn.cancel {
        background: #f0f0f0;
        color: #666;
    }

    .prompt-btn.cancel:hover {
        background: #e0e0e0;
    }

    .prompt-btn.confirm {
        background: #4a90d9;
        color: white;
    }

    .prompt-btn.confirm:hover {
        background: #3a80c9;
    }

    /* Modern UI overrides */
    :global(body) {
        background: var(--gradient-app);
        color: var(--color-text);
        font-family: var(--font-ui);
    }

    .epub-editor {
        background: rgba(238, 244, 248, 0.72);
        color: var(--color-text);
    }

    .file-tree {
        width: 260px;
        background: rgba(255, 255, 255, 0.82);
        border-right: 1px solid var(--color-border);
        box-shadow: 10px 0 30px rgba(23, 36, 52, 0.05);
        backdrop-filter: blur(16px);
    }

    .tree-header,
    .preview-header,
    .tabs-bar {
        background: rgba(255, 255, 255, 0.78);
        border-bottom: 1px solid var(--color-border);
        backdrop-filter: blur(18px) saturate(1.12);
    }

    .tree-header,
    .preview-header {
        height: 52px;
    }

    .tree-header {
        padding: 0 14px;
        justify-content: space-between;
    }

    .tree-header h3 {
        color: var(--color-text);
        font-size: 18px;
        font-weight: 800;
        letter-spacing: 0.01em;
    }

    .header-actions {
        gap: 8px;
    }

    .header-actions .icon-btn {
        width: 34px;
        min-width: 34px;
        height: 34px;
        padding: 0;
        white-space: nowrap;
        font-size: 16px;
        font-weight: 600;
        line-height: 1;
    }

    .icon-btn {
        width: 32px;
        height: 32px;
        border: 1px solid var(--color-border);
        border-radius: var(--radius-xs);
        background: rgba(255, 255, 255, 0.82);
        color: var(--color-text-soft);
        box-shadow: var(--shadow-xs);
        transition:
            transform var(--transition-fast),
            border-color var(--transition-fast),
            background var(--transition-fast),
            color var(--transition-fast),
            box-shadow var(--transition-fast);
    }

    .icon-btn:hover:not(:disabled) {
        background: var(--color-hover);
        border-color: var(--color-border-strong);
        color: var(--color-text);
        box-shadow: var(--shadow-sm);
